// Unit 3: Testing Strategies (Chapters 3–4, pp.59–78)
EXTRA_UNITS.push({
id:3, concepts:[
{title:"🎯 Learning Objectives",ref:"Module 3",content:`<p>By the end of this chapter you should be able to:</p><ul><li>Examine the <strong>4 basic testing approaches</strong> for software (Static / White Box / Black Box / Performance)</li><li>Explain when each approach is most effective during the SDLC</li><li>Apply specific <strong>techniques</strong> within each approach (coverage methods, boundary values, etc.)</li><li>Use the <strong>Testing Strategy Chessboard</strong> to plan WHAT to test × WHEN × on WHICH platform</li></ul><div class="zh-note">本章目标：掌握 4 种测试方法（静态/白盒/黑盒/性能）+ 每种里的具体技术 + 用棋盘规划"测什么 × 何时测 × 哪一层"。</div>`},
{title:"✈️ Boeing 299 + The Checklist Mentality",ref:"pp.59–60",content:`<p>In 1935, the <strong>Boeing Model 299</strong> crashed during a demonstration flight — but the design wasn't faulty. The elevator control locks weren't removed before takeoff. <strong>Nobody knew whose job it was.</strong></p><div style="background:var(--orange-bg);border-left:4px solid var(--orange);padding:14px 18px;border-radius:0 8px 8px 0;margin:14px 0;font-size:13.5px;">Boeing's response wasn't to redesign the plane — it was to invent the <strong>pilot's preflight checklist</strong>. Same plane, zero crashes after the checklist.</div><p><strong>Why this matters for software testers:</strong></p><ul><li>Most software failures aren't caused by clever bugs — they're caused by <strong>missed steps</strong></li><li>A <span class="key-term">structured checklist</span> ensures critical steps are never skipped, by anyone, ever</li><li>Testers borrow this philosophy: every test follows a documented procedure</li></ul><div class="callout"><strong>Modern parallel:</strong> CI/CD pipelines (GitHub Actions, GitLab CI) ARE digital checklists — they automate the "did everyone do their job" check on every commit.</div><div class="zh-note">波音 299 坠机不是设计缺陷，是流程遗漏——没人知道该谁拔起落锁。解决方案是检查清单。测试同理：用清单确保关键步骤永远不漏。</div>`},
{title:"🔤 SPRAE: The 5-Step Testing Checklist",ref:"pp.61–65",content:`<p>Dr. Edward L. Jones' framework — the testers' equivalent of the pilot's preflight checklist.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);width:40px;">Letter</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Meaning</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">What it means in practice</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:8px;font-weight:700;color:var(--blue);font-size:18px;">S</td><td style="padding:8px;font-weight:600;">Specification</td><td style="padding:8px;font-style:italic;">"No spec, no test." Written statement of expected behavior MUST exist first.</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:8px;font-weight:700;color:var(--purple);font-size:18px;">P</td><td style="padding:8px;font-weight:600;">Premeditation</td><td style="padding:8px;font-style:italic;">Test plans, environments, data, scripts, schedules — all planned UPFRONT.</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:8px;font-weight:700;color:var(--orange);font-size:18px;">R</td><td style="padding:8px;font-weight:600;">Repeatability</td><td style="padding:8px;font-style:italic;">Anyone can rerun the test and get the same result. Linked to <span class="key-term">CMMi</span> maturity model.</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:8px;font-weight:700;color:var(--green);font-size:18px;">A</td><td style="padding:8px;font-weight:600;">Accountability</td><td style="padding:8px;font-style:italic;">Prove the tester followed the plan. <strong>Defect correction = developer's job</strong>, not tester's.</td></tr><tr><td style="padding:8px;font-weight:700;color:var(--red);font-size:18px;">E</td><td style="padding:8px;font-weight:600;">Economy</td><td style="padding:8px;font-style:italic;">Testing cost-effectiveness + budget control.</td></tr></tbody></table><div class="callout important"><strong>Critical confusion:</strong> Accountability does NOT mean fixing defects. The TESTER reports; the DEVELOPER corrects. Mixing these roles destroys objectivity.</div><div class="zh-note">SPRAE = 规范(没规范别测) · 预谋(提前规划) · 可重复(谁来都得一样) · 问责(测试员报告，开发者修) · 经济(看 ROI)。</div>`},
{title:"♟️ The 4 Chess Pieces (Testing Approaches)",ref:"pp.66–70",content:`<p>The 4 fundamental testing approaches — like chess pieces, each has its own movement rules.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Approach</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Tests WITH</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Looks at</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">When (best)</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--blue);font-weight:600;">📄 Static</td><td style="padding:6px 8px;">Pencil + paper</td><td style="padding:6px 8px;">Documents · requirements · code (without running)</td><td style="padding:6px 8px;">Early — analysis / design</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--purple);font-weight:600;">🟦 White Box</td><td style="padding:6px 8px;">Source code</td><td style="padding:6px 8px;">Internal logic paths</td><td style="padding:6px 8px;">Preliminary construction</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--orange);font-weight:600;">⬛ Black Box</td><td style="padding:6px 8px;">Executable</td><td style="padding:6px 8px;">External behavior (input → output)</td><td style="padding:6px 8px;">Final construction</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;color:var(--red);font-weight:600;">⚡ Performance</td><td style="padding:6px 8px;">Executable + load</td><td style="padding:6px 8px;">Speed · throughput · stability</td><td style="padding:6px 8px;">Near end of dev</td></tr></tbody></table><div class="callout">All 4 are needed — no single one catches all defects. Static catches doc bugs cheap, white box catches logic bugs in modules, black box catches user-facing bugs, performance catches the speed problems that survive everything else.</div><div class="zh-note">4 个棋子：静态(看文档) · 白盒(看代码逻辑) · 黑盒(看输入输出) · 性能(看速度)。每个用在不同阶段，互补不重复。</div>`},
{title:"📄 Static Testing: When + Why (Hospital Example)",ref:"pp.66, Module 3",content:`<p><span class="key-term">Static testing</span> = testing WITHOUT executing code. Done early (especially design stage). Validates documents and code by reading.</p><p><strong>It answers:</strong> <em>"Are we building the right product?"</em> — Focus on user requirements and expectations.</p><p><strong>📋 Example: Login Requirement Doc</strong></p><div style="background:var(--bg-warm);padding:12px 16px;border-radius:8px;margin:10px 0;font-size:13px;border-left:3px solid var(--blue);"><em>Doc says:</em> "User enters username and password to login."<br><br><strong>Static testing catches:</strong><br>❌ No rule for invalid password<br>❌ No limit on login attempts<br>❌ No mention of error messages<br>✅ <strong>All caught BEFORE coding starts</strong></div><p><strong>🏥 Hospital Patient Check-In Scenario</strong> — 4 techniques applied:</p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Technique</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Issue Found</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Action</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">📋 Desk Check</td><td style="padding:6px 8px;">No rules for incomplete insurance info</td><td style="padding:6px 8px;">Update to handle missing data</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">🔍 Inspection</td><td style="padding:6px 8px;">Workflow lacks walk-in patient steps</td><td style="padding:6px 8px;">Update workflow</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">🚶 Walkthrough</td><td style="padding:6px 8px;">No emergency appointment procedure</td><td style="padding:6px 8px;">Add emergency handling</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;font-weight:600;">📢 Presentation</td><td style="padding:6px 8px;">No rules for late-arriving patients</td><td style="padding:6px 8px;">Add late-arrival procedure</td></tr></tbody></table><div class="callout important"><strong>4 benefits:</strong> ① Find defects early ② Improve productivity ③ Reduce dynamic-testing cost ④ Reduce late-stage defects.</div><div class="zh-note">静态测试 = 不运行代码，只审文档。早做最划算。医院例子：4 种技术(桌检/检视/走查/演示)各能发现不同的缺失。</div>`},
{title:"🔧 Static Testing: 2 Methods + Modern Tools",ref:"pp.66–67, Module 3",content:`<p>Static testing splits into <strong>2 distinct activities</strong>:</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);width:40%;">Method</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">What It Checks</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);vertical-align:top;"><td style="padding:8px;color:var(--blue);font-weight:600;">📝 1. Review Process<br><span style="font-weight:400;font-size:12px;color:var(--text-dim);">(human-driven)</span></td><td style="padding:8px;">Documents: requirements, design, specs.<br>Types: <strong>Informal review · Walkthrough · Inspection</strong>.<br>Goal: find errors, missing details, unclear info.</td></tr><tr style="background:var(--bg-warm);vertical-align:top;"><td style="padding:8px;color:var(--purple);font-weight:600;">🤖 2. Static Analysis<br><span style="font-weight:400;font-size:12px;color:var(--text-dim);">(tool-driven)</span></td><td style="padding:8px;">Code without running it.<br>Checks: <strong>Data flow</strong> · <strong>Control flow</strong> · <strong>Cyclomatic complexity</strong>.<br>Catches: unused/undefined vars · dead code · infinite loops · style violations.</td></tr></tbody></table><p><strong>Data flow vs Control flow:</strong></p><div style="background:var(--bg-warm);padding:10px 14px;border-radius:8px;margin:8px 0;font-size:13px;">📊 <strong>Data flow</strong> = how data moves through the system (in → transform → out)<br>🔀 <strong>Control flow</strong> = decision logic (which branches execute under what conditions)</div><p><strong>🛠️ Modern Static Analysis Tools:</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12.5px;"><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 10px;font-weight:600;width:30%;">Checkstyle</td><td style="padding:6px 10px;">Java code style enforcement</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 10px;font-weight:600;">Pylint</td><td style="padding:6px 10px;">Python errors + style</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 10px;font-weight:600;">Bandit</td><td style="padding:6px 10px;">Python security (hardcoded passwords, SQL injection)</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 10px;font-weight:600;">ESLint</td><td style="padding:6px 10px;">JavaScript / TypeScript</td></tr><tr><td style="padding:6px 10px;font-weight:600;">SourceMeter</td><td style="padding:6px 10px;">C, C++, Java, Python, RPG (multi-language)</td></tr></tbody></table><div class="zh-note">静态分两路：① 评审(人审文档) ② 静态分析(工具扫代码)。现代工具：Pylint(Python)、ESLint(JS)、Bandit(安全)、Checkstyle(Java)。</div>`},
{title:"🟦 White Box Testing: Internal Logic (Login Example)",ref:"pp.67",content:`<p>Also called <span class="key-term">structural testing</span> / <span class="key-term">code-based testing</span>. Tests INTERNAL workings — focus on "how the system works internally", not just what it produces.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">👨‍💻 Developer focus</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">🧪 Tester focus</th></tr></thead><tbody><tr><td style="padding:8px;">Positive testing — does the code WORK?</td><td style="padding:8px;">Negative testing — how does it FAIL?</td></tr></tbody></table><p><strong>🔐 Process: Testing a Login Module</strong></p><div style="background:var(--bg-warm);padding:14px 18px;border-radius:8px;margin:10px 0;font-size:13px;border-left:3px solid var(--purple);"><strong>Input:</strong> Requirement (user logs in) · Design doc (page structure) · Source code (auth program)<br><br><strong>Process:</strong><br>1️⃣ <strong>Risk analysis</strong> — weak password? unauthorized access?<br>2️⃣ <strong>Test planning</strong> — valid + invalid login attempts<br>3️⃣ <strong>Test case design:</strong><br>&nbsp;&nbsp;&nbsp;✅ Correct user + password → expect success<br>&nbsp;&nbsp;&nbsp;❌ Wrong password → expect error<br>&nbsp;&nbsp;&nbsp;⚠️ Empty fields → expect validation warning<br>4️⃣ <strong>Execution loop:</strong> Run → Found error (accepts empty password) → Fix → Re-run → Repeat<br>5️⃣ <strong>Reporting</strong> — record bugs found + fixed</div><div class="callout important"><strong>Requirement:</strong> Tester MUST know programming. Can't test code paths you don't understand. Languages: Java, C++, Python, etc.</div><div class="zh-note">白盒 = 看着源代码测内部逻辑。登录例子：风险分析 → 计划 → 设计测试用例(对/错/空) → 执行循环 → 报告。测试员必须懂编程。</div>`},
{title:"📊 White Box: 6 Coverage Techniques",ref:"pp.107–112",content:`<p>The 6 ways to measure "how thoroughly did we test the code." Each technique = stricter than the last.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);width:30px;">#</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Technique</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Rule</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--purple);">1</td><td style="padding:6px 8px;"><strong>Statement Coverage</strong></td><td style="padding:6px 8px;">Every <strong>line of code</strong> executes at least once</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--purple);">2</td><td style="padding:6px 8px;"><strong>Branch Coverage</strong></td><td style="padding:6px 8px;">Every TRUE and FALSE outcome of each IF</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--purple);">3</td><td style="padding:6px 8px;"><strong>Condition Coverage</strong></td><td style="padding:6px 8px;">Each individual condition in a compound IF tested both ways</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--purple);">4</td><td style="padding:6px 8px;"><strong>Multi-Condition Coverage</strong></td><td style="padding:6px 8px;">ALL combinations of conditions tested (2 vars = 4 cases)</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--purple);">5</td><td style="padding:6px 8px;"><strong>Path Coverage</strong></td><td style="padding:6px 8px;">Every possible <strong>full route</strong> through the code</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;font-weight:700;color:var(--purple);">6</td><td style="padding:6px 8px;"><strong>Basis Path Testing</strong></td><td style="padding:6px 8px;">Use <strong>cyclomatic complexity</strong> to find minimum independent paths</td></tr></tbody></table><p><strong>📝 Quick Example — Statement vs Branch Coverage:</strong></p><div style="background:var(--bg-warm);padding:12px 14px;border-radius:8px;margin:8px 0;font-family:'JetBrains Mono',monospace;font-size:12px;line-height:1.6;"><span style="color:var(--purple);">if</span> (marks &gt;= 50)<br>&nbsp;&nbsp;print(<span style="color:var(--green);">"Pass"</span>);<br><span style="color:var(--purple);">else</span><br>&nbsp;&nbsp;print(<span style="color:var(--red);">"Fail"</span>);<br>print(<span style="color:var(--blue);">"Exam Finished"</span>);</div><div style="background:var(--accent-bg);padding:10px 14px;border-radius:8px;margin:8px 0;font-size:13px;"><strong>Statement Coverage:</strong> Test marks=70 (covers Pass) + marks=30 (covers Fail). 2 tests → all lines run.<br><strong>Branch Coverage:</strong> Same 2 tests (TRUE + FALSE of the IF). In this case same as statement coverage.</div><p><strong>🔺 Cyclomatic Complexity</strong> = how many independent paths exist. Used to find the MINIMUM number of test cases. Triangle classifier (Equilateral/Isosceles/Scalene/Not-triangle) → CC = 4 → at least 4 tests required.</p><div class="callout">👉 Try the <strong>Coverage Visualizer</strong> in the Interactive tab — see code highlighted by technique.</div><div class="zh-note">白盒 6 法（由松到严）：语句→分支→条件→多条件→路径→基础路径(用圈复杂度算最少用例数)。</div>`},
{title:"⬛ Black Box Testing: Behavior (E-commerce Example)",ref:"pp.67",content:`<p>Also called <span class="key-term">behavioral testing</span> / <span class="key-term">specification-based testing</span>. Examines functionality WITHOUT looking inside the code.</p><div style="background:var(--bg-warm);padding:12px 16px;border-radius:8px;margin:10px 0;font-size:13px;">Testers know <strong>inputs</strong> and <strong>expected outputs</strong> — internal code, data structures, algorithms are NOT considered. Used at <strong>every level</strong>: unit, integration, system, acceptance.</div><p><strong>🛒 Example: E-commerce Login Page</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Input</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Expected Output</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Actual Output</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:8px;">Correct username/password</td><td style="padding:8px;color:var(--green);">✅ Login success</td><td style="padding:8px;color:var(--green);">✅ Login success</td></tr><tr style="background:var(--bg-warm);"><td style="padding:8px;">Wrong password</td><td style="padding:8px;color:var(--green);">✅ Error message</td><td style="padding:8px;color:var(--red);">❌ System crash!</td></tr></tbody></table><div class="callout important">Even WITHOUT seeing the code, the tester detected a critical defect — system crashes instead of showing error. This is the power of black box: it tests the system as USERS experience it.</div><p><strong>Required tester skills:</strong> Understand requirements · know user behavior · write test cases · basic logic.<br><strong>Tools:</strong> Selenium, JMeter, QTP, Postman.</p><div class="zh-note">黑盒 = 不看代码，只看输入和输出。电商登录例子：错密码本该报错却崩溃——黑盒一眼发现。每个测试层级都用。</div>`},
{title:"🧪 Black Box: 7 Techniques (Library + Login Examples)",ref:"pp.112–119",content:`<p>The 7 systematic ways to design black-box test cases.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px;text-align:left;color:var(--accent-dim);width:30px;">#</th><th style="padding:6px;text-align:left;color:var(--accent-dim);">Technique</th><th style="padding:6px;text-align:left;color:var(--accent-dim);">Example (Library System)</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px;font-weight:700;color:var(--orange);">1</td><td style="padding:6px;"><strong>Equivalence Partitioning</strong><br><span style="font-size:11px;color:var(--text-dim);">Divide inputs into valid/invalid groups</span></td><td style="padding:6px;font-style:italic;">Books borrowed: Valid=1–5, Invalid=0 or 10</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px;font-weight:700;color:var(--orange);">2</td><td style="padding:6px;"><strong>Boundary Value Analysis</strong><br><span style="font-size:11px;color:var(--text-dim);">Test edges of input range</span></td><td style="padding:6px;font-style:italic;">Max=5 → test 4, 5, 6</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px;font-weight:700;color:var(--orange);">3</td><td style="padding:6px;"><strong>Decision Table</strong><br><span style="font-size:11px;color:var(--text-dim);">All combinations of conditions</span></td><td style="padding:6px;font-style:italic;">Login: correct user × correct password = 4 combinations</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px;font-weight:700;color:var(--orange);">4</td><td style="padding:6px;"><strong>State Transition</strong><br><span style="font-size:11px;color:var(--text-dim);">System state changes</span></td><td style="padding:6px;font-style:italic;">Book: Available → Issued → Returned</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px;font-weight:700;color:var(--orange);">5</td><td style="padding:6px;"><strong>Error Guessing</strong><br><span style="font-size:11px;color:var(--text-dim);">Tester predicts likely errors</span></td><td style="padding:6px;font-style:italic;">Empty cart, invalid card number, paste emoji</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px;font-weight:700;color:var(--orange);">6</td><td style="padding:6px;"><strong>Use Case Testing</strong><br><span style="font-size:11px;color:var(--text-dim);">Real user workflows</span></td><td style="padding:6px;font-style:italic;">Search → Cart → Checkout → Payment</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px;font-weight:700;color:var(--orange);">7</td><td style="padding:6px;"><strong>Syntax Testing</strong><br><span style="font-size:11px;color:var(--text-dim);">Format/structure of input</span></td><td style="padding:6px;font-style:italic;">Email: test@test.com ✅ vs test@com ❌</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px;font-weight:700;color:var(--orange);">+</td><td style="padding:6px;"><strong>Cause–Effect Graphing</strong><br><span style="font-size:11px;color:var(--text-dim);">Maps inputs → outputs visually</span></td><td style="padding:6px;font-style:italic;">If (valid user AND password) → login success</td></tr></tbody></table><div class="callout"><strong>Where to use which:</strong> Equivalence + Boundary for input ranges · Decision Table for complex logic · State Transition for stateful systems · Use Case for end-to-end flows · Error Guessing as a "catch the rest" layer.</div><div class="zh-note">黑盒 7 法：等价类(分组取代表) · 边界值(测边缘) · 决策表(组合) · 状态转换 · 错误猜测 · 用例(端到端流程) · 语法测试 · 因果图。</div>`},
{title:"⚡ Performance Testing: Speed + Cash Register / Gas Pump",ref:"pp.129–148",content:`<p><strong>Non-functional testing</strong>. Doesn't ask "does it work?" — asks <strong>"is it fast enough under load?"</strong></p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Black/White Box checks…</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Performance checks…</th></tr></thead><tbody><tr><td style="padding:8px;">Business logic correctness · Requirements validation</td><td style="padding:8px;">⏱️ Speed · 🚀 Throughput under load · 💪 Stability</td></tr></tbody></table><p><strong>Failure conditions:</strong></p><ul><li>❌ Transactions too slow</li><li>❌ System can't handle required transaction volume</li></ul><p><strong>Real-World Performance Targets:</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Scenario</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Speed Goal</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Throughput</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">🛒 Cash register (retail)</td><td style="padding:6px 8px;">Few seconds per customer</td><td style="padding:6px 8px;">50–100 customers/hour</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">⛽ Gas pump authorization</td><td style="padding:6px 8px;">1–3 seconds</td><td style="padding:6px 8px;">Transactions per minute</td></tr><tr><td style="padding:6px 8px;font-weight:600;">🌐 E-commerce website</td><td style="padding:6px 8px;">&lt;3s page load</td><td style="padding:6px 8px;">Concurrent users handled</td></tr></tbody></table><p><strong>If performance fails, try (in order):</strong></p><div style="background:var(--bg-warm);padding:10px 14px;border-radius:8px;margin:8px 0;font-size:13px;">1️⃣ Faster hardware → 2️⃣ More memory → 3️⃣ More bandwidth → 4️⃣ More storage → 5️⃣ <strong>If none work: major redesign required.</strong></div><div class="callout important"><strong>When:</strong> Usually performed NEAR THE END of dev, after black/white box prove correctness. Performance is about speed, not correctness.</div><div class="zh-note">性能测试 = 看快不快 + 撑不撑得住。例子：收银机几秒/人，加油机 1-3 秒，电商 &lt;3 秒页面加载。优化顺序：硬件→内存→带宽→存储→重新设计。</div>`},
{title:"♟️ Testing Strategy Chessboard (2D + 3D)",ref:"pp.70–77",content:`<p>The master tool for test planning. Answers <strong>WHAT × WHEN × WHERE</strong>.</p><p><strong>📊 2D Chessboard:</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:13px;"><tbody><tr><td style="padding:8px;background:var(--bg-warm);font-weight:600;width:30%;">↔️ X-axis (columns)</td><td style="padding:8px;">Development phases: Prelim Investigation · Analysis · Design · Prelim Construction · Final Construction · Installation</td></tr><tr><td style="padding:8px;background:var(--bg-warm);font-weight:600;">↕️ Y-axis (rows)</td><td style="padding:8px;">The 4 testing approaches: Static · White Box · Black Box · Performance</td></tr><tr><td style="padding:8px;background:var(--bg-warm);font-weight:600;">Cells</td><td style="padding:8px;">Mark which approaches apply at which phases. Empty cells = "too late" or "not applicable"</td></tr></tbody></table><p><strong>🎲 3D Chessboard</strong> — adds a Z-axis: <strong>software platform layers</strong>:</p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12.5px;"><tbody><tr><td style="padding:6px 8px;background:var(--accent-bg);font-weight:600;color:var(--accent-dim);width:35%;">🖥️ Server layer</td><td style="padding:6px 8px;">Backend: data storage, processing, business logic</td></tr><tr><td style="padding:6px 8px;background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">💻 Workstation layer</td><td style="padding:6px 8px;">User-side: input, interface, display</td></tr></tbody></table><div class="callout">Both must be tested to ensure the entire system works across platforms.</div><div class="callout important"><strong>The chessboard answers 3 questions in one diagram:</strong> WHAT to test (approach) × WHEN to test (phase) × WHERE to test (platform layer).</div><div class="callout">👉 The <strong>Interactive tab → Chessboard</strong> shows this clickable. Each cell explains what testing happens at that intersection.</div><div class="zh-note">棋盘：2D = 测试方法 × 开发阶段。3D 多一维：服务器/工作站平台层。一图回答"测什么 × 何时测 × 哪一层"。</div>`},
{title:"🏦 Real Case: HSBC IT Outage (Feb 27, 2017)",ref:"Module 3 case",content:`<p>HSBC is one of the world's largest banks, serving <strong>~39 million customers</strong> globally. On <strong>Feb 27, 2017</strong>, their online banking went down — a major disruption, especially for business accounts.</p><div style="background:var(--red-bg);border-left:4px solid var(--red);padding:14px 18px;border-radius:0 8px 8px 0;margin:14px 0;"><strong style="color:var(--red);">⚠️ Impact:</strong><br><span style="font-size:13.5px;">Customers couldn't access accounts, pay bills, or run business operations for hours. For a bank that handles trillions in transactions, every minute of downtime = millions in lost revenue + customer trust eroded.</span></div><p><strong>How could the 4 testing approaches have prevented this?</strong></p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Testing Approach</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">What it would catch</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--blue);font-weight:600;">📄 Static</td><td style="padding:6px 8px;">Review change-management procedures → catch missing rollback plan in the deploy spec</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--purple);font-weight:600;">🟦 White Box</td><td style="padding:6px 8px;">Code review of session-management changes → spot the auth-server bug before it ships</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--orange);font-weight:600;">⬛ Black Box</td><td style="padding:6px 8px;">Test login + transaction flows in staging → reproduce the user-facing failure pre-release</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;color:var(--red);font-weight:600;">⚡ Performance</td><td style="padding:6px 8px;">Load test with realistic Monday-morning traffic → catch capacity issues before customers do</td></tr></tbody></table><div class="callout important"><strong>📈 Modern parallel:</strong> <strong>CrowdStrike (Jul 2024)</strong> — untested kernel driver brought down 8.5M Windows PCs, cost ~$5.4B. Same lesson: <em>insufficient testing of changes that affect millions of users</em>. The 4 chess pieces (especially Static + Performance) would have caught both.</div><div class="zh-note">2017 年 HSBC 全球银行因测试不足导致系统瘫痪，3900 万客户受影响。4 种测试方法每一种都能拦下不同的问题。CrowdStrike 2024 是同样教训的现代版。</div>`}
],quiz:[
{type:"mc",q:"SPRAE stands for:",options:["Specification, Planning, Repeatability, Analysis, Execution","Specification, Premeditation, Repeatability, Accountability, Economy","Strategy, Planning, Requirements, Assessment, Evaluation","Standards, Premeditation, Requirements, Accountability, Efficiency"],answer:1,explanation:"SPRAE = Specification, Premeditation, Repeatability, Accountability, Economy."},
{type:"mc",q:"'No specifications, no test' belongs to which SPRAE letter?",options:["Premeditation","Accountability","Specification","Economy"],answer:2,explanation:"Specification = written statement of expected behavior. Without it, nothing to test against."},
{type:"mc",q:"In SPRAE, who corrects defects found during testing?",options:["The tester","The test manager","The developer","The business analyst"],answer:2,explanation:"Defect correction is the developer's accountability, not the tester's. Mixing these roles destroys objectivity."},
{type:"mc",q:"Reviewing documents WITHOUT executing software is:",options:["Black box testing","White box testing","Performance testing","Static testing"],answer:3,explanation:"Static = 'not while executing.' It reviews documents and code by reading."},
{type:"mc",q:"Which testing approach is BEST suited for the early Design phase?",options:["Performance","Static","White Box","Black Box"],answer:1,explanation:"Static is done early — especially Design — because it tests documents before code exists. Cheapest defect-removal stage."},
{type:"mc",q:"Static testing has TWO methods. Static Analysis specifically:",options:["Reviews documents in a meeting","Checks code without running it, using tools","Tests with end users","Measures load capacity"],answer:1,explanation:"2 methods: (1) Review Process — human-driven, checks documents. (2) Static Analysis — tool-driven, checks code without execution. Tools: Pylint, ESLint, Bandit, SourceMeter."},
{type:"mc",q:"Which of these is a static analysis tool for Python?",options:["Selenium","Pylint","JMeter","Postman"],answer:1,explanation:"Pylint analyzes Python code for errors + style. ESLint = JS. Bandit = Python security. Checkstyle = Java."},
{type:"mc",q:"White box testing requires the tester to:",options:["Know nothing about the code","Have access to source code and understand programming","Test only the UI","Generate synthetic users"],answer:1,explanation:"White box = structural / code-based testing. Tester MUST know the programming language (Java, Python, etc.) to write tests that hit code paths."},
{type:"mc",q:"Which white-box technique requires EVERY line of code to execute at least once?",options:["Branch coverage","Statement coverage","Path coverage","Loop coverage"],answer:1,explanation:"Statement coverage — execute every statement at least once. Branch coverage is stricter (every TRUE/FALSE outcome). Path is strictest (every possible route)."},
{type:"mc",q:"Cyclomatic complexity is used in which technique?",options:["Statement coverage","Boundary value analysis","Basis path testing","Decision table"],answer:2,explanation:"Basis Path Testing uses cyclomatic complexity to compute the MINIMUM number of independent test cases needed."},
{type:"mc",q:"Black box testing requires the tester to:",options:["Read source code","Know inputs and expected outputs only","Be a senior developer","Modify the code"],answer:1,explanation:"Black box = behavioral / specification-based. Tester knows ONLY inputs and expected outputs. Internal code is invisible. Often called 'specification-based testing'."},
{type:"mc",q:"Testing values 4, 5, and 6 when the max borrowing limit is 5 is which technique?",options:["Equivalence Partitioning","Boundary Value Analysis","Decision Table","Error Guessing"],answer:1,explanation:"Boundary Value Analysis tests at edges: max=5, just below (4), and just above (6). Most defects hide at boundaries."},
{type:"mc",q:"Testing 'Available → Issued → Returned' for a library book is which technique?",options:["Use Case Testing","State Transition Testing","Equivalence Partitioning","Syntax Testing"],answer:1,explanation:"State Transition tests system state changes. Books, orders, sessions, workflow approvals all use this."},
{type:"mc",q:"Performance testing typically happens:",options:["At the very start, before design","Near the END of development, after black/white box","Only after deployment","Continuously during all phases"],answer:1,explanation:"Performance testing comes near the END — software must be stable (correctness verified by black/white box) before measuring speed and load."},
{type:"mc",q:"On the 2D Chess Board, COLUMNS represent:",options:["Testing approaches","Platform layers","Development lifecycle phases","Defect severity"],answer:2,explanation:"Columns = development phases (X-axis). Rows = testing approaches (Y-axis). 3D adds platform layers (Z-axis)."},
{type:"mc",q:"The 3D Chess Board's Z-axis (third dimension) is:",options:["Defect severity","Software platform layers (Server / Workstation)","Cost categories","Team roles"],answer:1,explanation:"Z-axis adds platform layers — Server (backend, data, processing) and Workstation (UI, input). Both must be tested."},
{type:"sa",q:"Explain the Boeing 299 lesson for software testing.",sampleAnswer:"The Boeing 299 crashed not from a design flaw but because control locks weren't removed — no procedure defined who should do it. The fix was a preflight checklist. Software testing applies the same lesson: structured checklists ensure critical steps are never missed. CI/CD pipelines today are the digital version of this checklist.",keywords:["checklist","crash","control locks","procedure","not design flaw","CI/CD"]},
{type:"sa",q:"Compare white box and black box testing.",sampleAnswer:"White box requires source code access — verifies internal logic (statement, branch, condition, path coverage). Tester must know programming. Black box does NOT use source code — tests external behavior by comparing actual outputs against expected outputs. Tester only needs to know inputs and expected outputs. White box catches logic bugs; black box catches user-facing bugs.",keywords:["source code","internal","logic","behavior","output","input","coverage","programming"]},
{type:"sa",q:"For the hospital check-in scenario, name the 4 static testing techniques and what each catches.",sampleAnswer:"1. Desk Checking — author/reviewer reads the doc; catches incomplete data rules. 2. Inspection — small team reviews workflow diagram; catches missing process steps (e.g., walk-in patients). 3. Walkthrough — manager guides team through each step; catches missing edge cases (e.g., emergency appointments). 4. Presentation — doc presented to front-desk staff; catches missing user-facing rules (e.g., late arrivals).",keywords:["desk check","inspection","walkthrough","presentation","incomplete","missing"]},
{type:"sa",q:"SCENARIO: A login system accepts 'admin/admin' as wrong credentials but doesn't show an error — the page just refreshes. Which testing approach catches this most easily? Why?",sampleAnswer:"Black box testing. It compares actual output vs expected: expected = 'error message', actual = 'silent refresh'. Black box catches this without needing to know the auth code internals. White box would also catch it if the tester examined the error-handling code paths, but black box is faster and reproduces the user experience.",keywords:["black box","expected","actual","behavior","output","user experience"]},
{type:"mc",q:"SCENARIO: Your team needs to test that 'Search → Add to Cart → Checkout → Payment' works end-to-end. Best black-box technique?",options:["Equivalence Partitioning","State Transition","Use Case Testing","Syntax Testing"],answer:2,explanation:"Use Case Testing — designed for testing real user workflows end-to-end across multiple screens/features. Equivalence/boundary work for single inputs, not full flows."},
{type:"mc",q:"SCENARIO: An e-commerce site times out under Black Friday traffic. Static and black-box tests passed. What did the team likely skip?",options:["More static reviews","Performance testing under realistic load","Pre-checking the database schema","More unit tests"],answer:1,explanation:"Performance testing checks speed and throughput UNDER LOAD. Correctness (static + black box) was fine — but the system couldn't handle the realistic traffic volume. Always load-test with worst-case scenarios (Black Friday, Cyber Monday)."}
]});

// ============================================================
INTERACTIVES[3] = function(el) {
  let u3Tab = 0;
  const tabs = [
    {key:'chess', icon:'♟️', label:'Testing Chessboard'},
    {key:'cover', icon:'📊', label:'Coverage Visualizer'},
    {key:'bb',    icon:'🧪', label:'Black Box Picker'}
  ];

  // ---------- Widget 1: Chessboard ----------
  const phases = ['Prelim Invest','Analysis','Design','Prelim Constr','Final Constr','Installation'];
  const approaches = [
    {name:'📄 Static',color:'#4a7fb5'},
    {name:'🟦 White Box',color:'#7c6baf'},
    {name:'⬛ Black Box',color:'#c08530'},
    {name:'⚡ Performance',color:'#c25450'}
  ];
  const appData = { '📄 Static':[1,1,1,1,1,0], '🟦 White Box':[0,0,0,1,1,0], '⬛ Black Box':[0,0,0,0,1,1], '⚡ Performance':[0,0,0,0,1,0] };
  const platData = { '📄 Static':[1,1,1,0,0,0], '🟦 White Box':[0,0,0,0,0,0], '⬛ Black Box':[0,0,0,1,1,0], '⚡ Performance':[0,0,0,0,1,0] };
  const cbDetails = {
    app: {
      '📄 Static-0':'Review problem definition + project goals for completeness.',
      '📄 Static-1':'Static test requirements, use cases, functional components matrix.',
      '📄 Static-2':'Review design docs: UI specs, data designs, interface specs.',
      '📄 Static-3':'Developers desk-check code. Senior inspections. Walk-throughs of complex modules.',
      '📄 Static-4':'Review integration docs. Static test changed specifications.',
      '🟦 White Box-3':'Developer unit testing: statement, branch, loop coverage on each module.',
      '🟦 White Box-4':'Integration-level white box across integrated modules.',
      '⬛ Black Box-4':'Test team functional testing: navigation, screens, flows, reports, DB CRUD. + Regression.',
      '⬛ Black Box-5':'Post-deployment user acceptance. Smoke testing. UAT validation.',
      '⚡ Performance-4':'Full perf testing: workload planning, ramp-up/down, round trip, stress, endurance.'
    },
    platform: {
      '📄 Static-0':'Review tech requirements: OS, DB, network, security platforms needed.',
      '📄 Static-1':'Static test platform specs: connectivity, data resources, security.',
      '📄 Static-2':'Evaluate + test platform candidates (DB, hardware, network) EARLY.',
      '⬛ Black Box-3':'Interface testing (4-step). Security with equivalence classes. Installation testing.',
      '⬛ Black Box-4':'Smoke, administration, backup/recovery on integrated platform.',
      '⚡ Performance-4':'Platform perf impact: security overhead, network latency, DB response.'
    }
  };
  let cbLayer = 'app';
  let cbSel = null;

  function renderChess() {
    const data = cbLayer==='app'?appData:platData;
    let h = '<p style="font-size:13px;color:var(--text-dim);margin-bottom:10px;">Click any cell to see what testing happens at that <strong>approach × phase</strong> intersection.</p>';
    h += '<div style="display:flex;gap:6px;margin-bottom:14px;">';
    h += '<button onclick="window._u3cbLayer(\'app\')" style="padding:7px 14px;font-size:12.5px;border-radius:8px;cursor:pointer;border:2px solid '+(cbLayer==='app'?'var(--accent)':'var(--border-light)')+';background:'+(cbLayer==='app'?'var(--accent-bg)':'var(--surface)')+';color:'+(cbLayer==='app'?'var(--accent-dim)':'var(--text-dim)')+';font-weight:600;transition:all .15s;">📱 Application Layer (2D)</button>';
    h += '<button onclick="window._u3cbLayer(\'platform\')" style="padding:7px 14px;font-size:12.5px;border-radius:8px;cursor:pointer;border:2px solid '+(cbLayer==='platform'?'var(--accent)':'var(--border-light)')+';background:'+(cbLayer==='platform'?'var(--accent-bg)':'var(--surface)')+';color:'+(cbLayer==='platform'?'var(--accent-dim)':'var(--text-dim)')+';font-weight:600;transition:all .15s;">🖥️ Platform Layer (3D)</button>';
    h += '</div>';
    h += '<div style="display:grid;grid-template-columns:130px repeat(6,1fr);gap:3px;">';
    h += '<div></div>';
    phases.forEach(p => h+='<div style="padding:8px 4px;font-size:10.5px;text-align:center;color:var(--accent-dim);background:var(--accent-bg);border-radius:6px;line-height:1.3;font-weight:600;">'+p+'</div>');
    approaches.forEach(a => {
      h += '<div style="padding:10px;font-size:12.5px;font-weight:700;background:var(--surface2);border-radius:6px;display:flex;align-items:center;color:'+a.color+';">'+a.name+'</div>';
      phases.forEach((p,pi) => {
        const yes = data[a.name][pi];
        const isSel = cbSel === a.name+'-'+pi;
        h += '<div onclick="window._u3cbClick(\''+a.name+'\','+pi+')" style="cursor:pointer;padding:10px;text-align:center;border-radius:6px;font-size:18px;border:2px solid '+(isSel?a.color:'var(--border-light)')+';background:'+(yes?(isSel?'var(--bg-warm)':a.color+'22'):'var(--surface2)')+';opacity:'+(yes?1:0.3)+';transition:all .15s;color:'+(yes?a.color:'var(--text-light)')+';font-weight:700;">'+(yes?'✓':'·')+'</div>';
      });
    });
    h += '</div>';
    h += '<div id="_u3cbDetail" style="margin-top:14px;padding:14px 18px;background:var(--bg-warm);border-radius:10px;font-size:13px;line-height:1.7;min-height:60px;color:var(--text);">Click any ✓ cell above to explore.</div>';
    return h;
  }
  window._u3cbLayer = function(l) { cbLayer=l; cbSel=null; rerender(); };
  window._u3cbClick = function(a,pi) {
    cbSel = a+'-'+pi;
    rerender();
    const key = a+'-'+pi;
    const d = cbDetails[cbLayer][key];
    const det = document.getElementById('_u3cbDetail');
    if (det) {
      if (d) det.innerHTML = '<div style="font-weight:700;color:var(--accent-dim);margin-bottom:6px;font-size:14px;">'+a+' × '+phases[pi]+'</div>'+d;
      else det.innerHTML = '<div style="font-weight:700;color:var(--text-dim);margin-bottom:6px;font-size:14px;">'+a+' × '+phases[pi]+'</div>This approach is typically NOT applied at this phase on the '+(cbLayer==='app'?'application':'platform')+' level.';
    }
  };

  // ---------- Widget 2: Coverage Visualizer ----------
  const covTechniques = [
    {key:'stmt',label:'Statement',color:'#4a7fb5',desc:'Every line executes at least once',
      tests:[{input:'marks = 70',covers:[1,2,5]},{input:'marks = 30',covers:[1,3,4,5]}],
      all:'Need BOTH tests to cover all 5 lines.'},
    {key:'branch',label:'Branch',color:'#7c6baf',desc:'Every TRUE/FALSE outcome of each IF',
      tests:[{input:'marks = 70 (TRUE branch)',covers:[1,2,5]},{input:'marks = 30 (FALSE branch)',covers:[1,3,4,5]}],
      all:'Same 2 tests cover both branches of the IF. Branch = Statement in this simple example.'},
    {key:'cond',label:'Condition',color:'#c08530',desc:'Each individual condition tested both ways',
      tests:[{input:'(this example has only 1 condition)',covers:[1,2,3,4,5]}],
      all:'For compound IF like (X==0 || Y==0): need X true/false AND Y true/false separately.'},
    {key:'path',label:'Path',color:'#3d8b5a',desc:'Every possible route through the code',
      tests:[{input:'marks = 70 → path A',covers:[1,2,5]},{input:'marks = 30 → path B',covers:[1,3,4,5]}],
      all:'Only 2 paths in this simple example. For nested IFs, paths multiply fast!'}
  ];
  const codeLines = [
    'if (marks >= 50) {',
    '  print("Pass");',
    '} else {',
    '  print("Fail");',
    '}',
    'print("Exam Finished");'
  ];
  let covSel = 0;
  let covTestSel = 0;

  function renderCover() {
    const tech = covTechniques[covSel];
    let h = '<p style="font-size:13px;color:var(--text-dim);margin-bottom:12px;">See how each coverage technique tests the same code snippet. Click a technique and a test case.</p>';
    h += '<div style="display:flex;gap:6px;margin-bottom:14px;flex-wrap:wrap;">';
    covTechniques.forEach((t,i) => {
      const active = i===covSel;
      h += '<button onclick="window._u3cov('+i+')" style="cursor:pointer;padding:8px 14px;border-radius:8px;border:2px solid '+(active?t.color:'var(--border-light)')+';background:'+(active?'var(--bg-warm)':'var(--surface)')+';color:'+(active?t.color:'var(--text-dim)')+';font-weight:700;font-size:12.5px;transition:all .15s;">'+t.label+'</button>';
    });
    h += '</div>';
    h += '<div style="background:var(--bg-warm);padding:14px 16px;border-radius:8px;font-size:13px;margin-bottom:14px;border-left:3px solid '+tech.color+';"><strong style="color:'+tech.color+';">'+tech.label+' Coverage:</strong> '+tech.desc+'</div>';
    h += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;">';
    h += '<div><div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:var(--text-dim);margin-bottom:6px;">📝 Code (highlighted = executed)</div><div style="background:#1e1b14;color:#e8e4d8;border-radius:8px;padding:14px;font-family:\'JetBrains Mono\',monospace;font-size:12.5px;line-height:1.9;">';
    const coverMap = {};
    if (tech.tests[covTestSel]) tech.tests[covTestSel].covers.forEach(c => coverMap[c]=true);
    codeLines.forEach((line,i) => {
      let cov;
      if (i===0) cov = coverMap[1];
      else if (i===1) cov = coverMap[2];
      else if (i===2) cov = coverMap[3];
      else if (i===3) cov = coverMap[4];
      else if (i===4) cov = coverMap[3]||coverMap[4];
      else if (i===5) cov = coverMap[5];
      h += '<div style="padding:2px 8px;border-radius:4px;background:'+(cov?tech.color+'40':'transparent')+';color:'+(cov?'#fff':'#a8a190')+';transition:all .3s;"><span style="opacity:0.4;margin-right:8px;">'+(i+1).toString().padStart(2,' ')+'</span>'+line.replace(/ /g,'&nbsp;')+'</div>';
    });
    h += '</div></div>';
    h += '<div><div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:var(--text-dim);margin-bottom:6px;">🧪 Test Cases</div>';
    tech.tests.forEach((t,i) => {
      const sel = i===covTestSel;
      h += '<div onclick="window._u3covTest('+i+')" style="cursor:pointer;background:'+(sel?'var(--accent-bg)':'var(--surface)')+';border:2px solid '+(sel?'var(--accent)':'var(--border-light)')+';padding:10px 14px;border-radius:8px;margin-bottom:8px;font-size:12.5px;color:var(--text);transition:all .15s;"><strong>Test '+(i+1)+':</strong> <code style="font-family:\'JetBrains Mono\',monospace;background:var(--surface2);padding:1px 5px;border-radius:3px;">'+t.input+'</code></div>';
    });
    h += '<div style="background:var(--accent-bg);padding:10px 12px;border-radius:8px;font-size:12px;color:var(--accent-dim);margin-top:10px;"><strong>📌 Insight:</strong> '+tech.all+'</div>';
    h += '</div></div>';
    return h;
  }
  window._u3cov = function(i){ covSel=i; covTestSel=0; rerender(); };
  window._u3covTest = function(i){ covTestSel=i; rerender(); };

  // ---------- Widget 3: Black Box Technique Picker ----------
  const bbScenarios = [
    {scenario:'You need to test a "Number of books to borrow" field that accepts 1–5. Test inputs: 0, 3, 6.',
      correct:0,explain:'Equivalence Partitioning — you grouped inputs into valid (1–5) and invalid (0, 6+) groups, then picked one representative from each.'},
    {scenario:'For the same field, you test values 4, 5, and 6 (specifically the edges of the valid range).',
      correct:1,explain:'Boundary Value Analysis — focus on edges (max=5), just below (4), just above (6). Most defects hide at boundaries.'},
    {scenario:'You build a table covering ALL combinations of "user exists × password correct" (4 rows).',
      correct:2,explain:'Decision Table — testing all combinations of conditions systematically.'},
    {scenario:'You test a library book transitioning: Available → Issued → Returned → Available.',
      correct:3,explain:'State Transition Testing — verifying the system correctly handles state changes over time.'},
    {scenario:'Based on experience, you test "what if user double-clicks Submit?" and "what if they paste emoji into the email field?"',
      correct:4,explain:'Error Guessing — using experience to predict likely failure scenarios not covered by formal techniques.'},
    {scenario:'You test the complete flow: Search product → Add to cart → Checkout → Enter shipping → Pay.',
      correct:5,explain:'Use Case Testing — testing real end-to-end user workflows across multiple screens/features.'},
    {scenario:'You test email field with: "test@test.com" (valid), "test@com" (no domain), "test.com" (no @).',
      correct:6,explain:'Syntax Testing — verifying input format/structure validation.'}
  ];
  const bbTechniques = [
    {key:0,label:'Equivalence Partitioning'},
    {key:1,label:'Boundary Value Analysis'},
    {key:2,label:'Decision Table'},
    {key:3,label:'State Transition'},
    {key:4,label:'Error Guessing'},
    {key:5,label:'Use Case Testing'},
    {key:6,label:'Syntax Testing'}
  ];
  let bbSel = 0;
  let bbPicked = null;

  function renderBB() {
    const s = bbScenarios[bbSel];
    let h = '<p style="font-size:13px;color:var(--text-dim);margin-bottom:12px;">Read the scenario, pick the technique you\'d use. See if you match the expert answer.</p>';
    h += '<div style="display:flex;gap:6px;margin-bottom:14px;flex-wrap:wrap;align-items:center;">';
    h += '<span style="font-size:12px;color:var(--text-dim);">Scenario:</span>';
    bbScenarios.forEach((_,i)=>{
      const sel = i===bbSel;
      h += '<button onclick="window._u3bb('+i+')" style="cursor:pointer;width:32px;height:28px;border-radius:6px;border:2px solid '+(sel?'var(--accent)':'var(--border-light)')+';background:'+(sel?'var(--accent-bg)':'var(--surface)')+';color:'+(sel?'var(--accent-dim)':'var(--text-dim)')+';font-weight:700;font-size:12px;transition:all .15s;">'+(i+1)+'</button>';
    });
    h += '</div>';
    h += '<div style="background:var(--bg-warm);padding:16px 20px;border-radius:10px;font-size:13.5px;margin-bottom:14px;border-left:3px solid var(--accent);line-height:1.7;"><strong style="color:var(--accent-dim);">📋 Scenario '+(bbSel+1)+':</strong> '+s.scenario+'</div>';
    h += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:14px;">';
    bbTechniques.forEach(t => {
      let bg='var(--surface)', border='var(--border-light)', color='var(--text-dim)';
      if (bbPicked !== null) {
        if (t.key === s.correct) { bg='var(--green-bg)'; border='var(--green)'; color='var(--green)'; }
        else if (t.key === bbPicked) { bg='var(--red-bg)'; border='var(--red)'; color='var(--red)'; }
      }
      h += '<button onclick="window._u3bbPick('+t.key+')" '+(bbPicked!==null?'disabled':'')+' style="cursor:'+(bbPicked!==null?'default':'pointer')+';padding:10px 14px;border-radius:8px;border:2px solid '+border+';background:'+bg+';color:'+color+';font-weight:600;font-size:12.5px;text-align:left;transition:all .15s;">'+t.label+(bbPicked!==null && t.key===s.correct?' ✓':'')+(bbPicked!==null && t.key===bbPicked && t.key!==s.correct?' ✗':'')+'</button>';
    });
    h += '</div>';
    if (bbPicked !== null) {
      const ok = bbPicked === s.correct;
      h += '<div style="padding:14px 18px;border-radius:10px;background:'+(ok?'var(--green-bg)':'var(--orange-bg)')+';border:2px solid '+(ok?'var(--green)':'var(--orange)')+';font-size:13px;color:var(--text);"><strong style="color:'+(ok?'var(--green)':'var(--orange)')+';">'+(ok?'✅ Correct!':'⚠️ Almost — the better answer is highlighted above.')+'</strong><br><br>'+s.explain+'</div>';
    } else {
      h += '<div style="padding:12px 16px;border-radius:8px;background:var(--surface2);font-size:12.5px;color:var(--text-dim);">👆 Pick a technique to see if it matches.</div>';
    }
    return h;
  }
  window._u3bb = function(i){ bbSel=i; bbPicked=null; rerender(); };
  window._u3bbPick = function(k){ bbPicked=k; rerender(); };

  // ---------- Main render with tabs ----------
  function rerender() {
    let h = '<div style="display:flex;gap:2px;margin-bottom:18px;background:var(--surface2);padding:3px;border-radius:10px;width:fit-content;border:1px solid var(--border-light);">';
    tabs.forEach((t,i) => {
      const active = i===u3Tab;
      h += '<button onclick="window._u3tab('+i+')" style="cursor:pointer;padding:8px 16px;border-radius:8px;border:none;background:'+(active?'var(--accent)':'transparent')+';color:'+(active?'#fff':'var(--text-dim)')+';font-size:13px;font-weight:600;transition:all .15s;">'+t.icon+' '+t.label+'</button>';
    });
    h += '</div>';
    h += '<div style="animation:u3fade 0.3s ease-out;">';
    if (u3Tab===0) h += renderChess();
    else if (u3Tab===1) h += renderCover();
    else h += renderBB();
    h += '</div>';
    h += '<style>@keyframes u3fade{from{opacity:0;transform:translateX(-8px);}to{opacity:1;transform:translateX(0);}}</style>';
    el.innerHTML = h;
  }
  window._u3tab = function(i){ u3Tab=i; rerender(); };
  rerender();
};

