MODERN_NOTES['3-1'] = {
  title: 'Boeing 299 → modern CI/CD pipelines = digital preflight checklists',
  year: '2026',
  content: 'The checklist mentality is literally embedded in modern dev workflow. <strong>GitHub Actions / GitLab CI</strong> run a fixed checklist on every commit: lint → unit tests → integration tests → security scan → deploy to staging → smoke tests. Like the pilot\'s preflight, no one can forget a step because automation enforces it. Companies that disabled CI checks (Knight Capital 2012, $440M loss in 45 min; CrowdStrike Jul 2024, $5.4B) prove the lesson never expires.'
};
MODERN_NOTES['3-2'] = {
  title: 'SPRAE maps perfectly to Agile/DevOps',
  year: '2026',
  content: '<strong>S</strong> = User stories &amp; acceptance criteria (Gherkin / BDD) · <strong>P</strong> = Sprint planning &amp; CI/CD pipeline setup · <strong>R</strong> = Automated test suites on every commit · <strong>A</strong> = Definition of Done (DoD) proves testing was completed · <strong>E</strong> = Story points + velocity tracking for cost-effectiveness. The framework is timeless — only the tools have changed.'
};
MODERN_NOTES['3-3'] = {
  title: 'The Testing Pyramid + Trophy complement the chess board',
  year: '2026',
  content: 'Modern testing adds the <strong>Testing Pyramid</strong>: many <strong>unit tests</strong> (fast, cheap) → fewer <strong>integration tests</strong> → fewest <strong>E2E/UI tests</strong> (slow, expensive). Kent C. Dodds\' updated <strong>Testing Trophy</strong> elevates integration tests as the highest-ROI tier. Chess board says WHAT &amp; WHEN; pyramid says HOW MANY. <strong>API / contract testing</strong> (Pact, Spring Cloud Contract) is now a critical middle layer for microservices.'
};
MODERN_NOTES['3-5'] = {
  title: 'Modern static analysis: SonarQube, GitHub CodeQL, Snyk',
  year: '2026',
  content: 'The 2007 tools (Checkstyle, Pylint, ESLint) still exist but are now wrapped in modern platforms: <strong>SonarQube / SonarCloud</strong> — quality gates that block merges if code smells, bugs, or coverage drop. <strong>GitHub CodeQL</strong> — Microsoft\'s semantic analysis, finds OWASP Top 10 vulnerabilities. <strong>Snyk</strong> — scans your dependencies (npm/PyPI) for known CVEs. <strong>Semgrep</strong> — custom rule scanning. All run automatically in PR checks; bad code never reaches main.'
};
MODERN_NOTES['3-7'] = {
  title: 'Code coverage in CI/CD: Istanbul, JaCoCo, Codecov',
  year: '2026',
  content: 'The 6 coverage techniques (statement, branch, condition, etc.) are now measured automatically by tools and tracked in PR comments. <strong>Istanbul / nyc</strong> (JavaScript), <strong>JaCoCo</strong> (Java), <strong>coverage.py</strong> (Python), <strong>llvm-cov</strong> (C++). <strong>Codecov / Coveralls</strong> aggregate results across PRs, fail builds if coverage drops below threshold (typically 80%). Modern teams set policies like "no merge if coverage drops by &gt;2%". <strong>Mutation testing</strong> (Stryker, PIT) takes it further by mutating code to verify tests actually catch bugs.'
};
MODERN_NOTES['3-9'] = {
  title: 'Modern black box: Cypress, Playwright, Postman, AI test generation',
  year: '2026',
  content: 'The 2007 tools (Selenium, JMeter, QTP) are being replaced: <strong>Cypress &amp; Playwright</strong> dominate modern browser testing — Selenium is the legacy choice. <strong>Postman / Bruno / Hoppscotch</strong> for API testing. <strong>k6</strong> for performance/load (replaces JMeter). New 2024+ category: <strong>AI test generators</strong> — <strong>Mabl, Testim, Functionize</strong> write test cases from user-flow recordings; <strong>Anthropic Claude / GPT-4</strong> generate test cases from Jira tickets. The 7 techniques (equivalence, boundary, etc.) are still the conceptual basis — AI just automates writing them.'
};
MODERN_NOTES['3-10'] = {
  title: 'Modern performance: k6, Lighthouse, Core Web Vitals',
  year: '2026',
  content: 'The cash-register example is now measured at web scale. <strong>Google Lighthouse</strong> + <strong>Core Web Vitals</strong> (LCP, FID, CLS, INP) are SEO-mandatory metrics. <strong>k6</strong> (modern JMeter) — script load tests in JavaScript. <strong>Gatling</strong> — Scala-based, enterprise scale. <strong>Datadog / New Relic / Grafana</strong> — production performance observability (the "passive testing" from Module 2). Modern SLO targets: P95 page load &lt;2.5s, API response &lt;200ms, 99.9% uptime (43 min downtime/month max).'
};
MODERN_NOTES['3-11'] = {
  title: 'Chessboard meets DevOps: shift-left + shift-right',
  year: '2026',
  content: 'The 2D chessboard\'s "what testing per phase" evolved into <strong>shift-left</strong> (test earlier — static analysis in IDE, tests in PR) + <strong>shift-right</strong> (test in production — feature flags, canary deploys, A/B tests, real-user monitoring). Modern teams test EVERY phase: pre-commit hooks (static) → CI (unit + integration) → staging (E2E) → canary (5% traffic) → full rollout → monitoring. The chessboard cells got denser, not fewer.'
};
MODERN_NOTES['3-12'] = {
  title: 'HSBC 2017 → CrowdStrike 2024: same lesson, bigger blast radius',
  year: '2024',
  content: 'HSBC\'s 2017 outage was contained to one bank\'s customers. <strong>CrowdStrike (Jul 19, 2024)</strong> — an untested Falcon sensor update bricked <strong>8.5 million Windows machines</strong> globally. Hospitals couldn\'t admit patients. 5,000+ flights canceled. Banks froze. Estimated cost: <strong>$5.4 BILLION</strong>. Root cause: a configuration file change skipped staged rollout — no canary testing, no progressive deployment. Every chess-piece (static review of the deploy script, white-box test of the parser, black-box test of the update, performance test of update propagation) would have caught it. The lesson hasn\'t changed since 1935 — just the blast radius has.'
};
